const input = $input.first().json;
const body = input.body || input;
const userText = body.text || '';
const conversationId = body.conversation_id || '';

if (!userText.trim()) {
  return [{
    json: {
      hasError: true,
      error: 'No voice command text provided.',
      userText: '',
      conversationId
    }
  }];
}

const systemPrompt = `You are a home media controller for a Plex media system. Your job is to parse voice commands and return structured JSON.

AVAILABLE ROOMS AND THEIR PLEX PLAYERS:
- "living room" = media_player.plex_plex_for_samsung_tv_2021
- "boys room" or "boys" = media_player.plex_plex_for_samsung_tv_2021_2
- "master" or "master bedroom" or "bedroom" = media_player.master_tv
- "all" or "all TVs" or "everywhere" or "every room" = use entity_id "all" and room "all" (targets every TV simultaneously)

AVAILABLE PLEX LIBRARIES:
- movies (media_content_type: MOVIE)
- tv or "tv shows" (media_content_type: EPISODE)
- p90x (media_content_type: VIDEO, library: P90X)
- youtube (media_content_type: VIDEO, library: YouTube)

AVAILABLE COMMANDS:
- play: Start playing specific media content on a specific TV
- pause: Pause the currently playing media on a specific TV
- resume: Resume paused media on a specific TV
- stop: Stop media playback on a specific TV

RULES:
1. If the user says "play [title]" without specifying a room, ask which room (set action to "error" with a helpful message)
2. If the user says "play" without a title, set action to "error"
3. For pause/resume/stop, if no room is specified, set action to "error" asking which room
4. Default library is "movies" if not specified
5. For TV shows, try to extract season and episode if mentioned (e.g. "play breaking bad season 3 episode 5")
6. Be flexible with room names: "living room", "the living room", "downstairs TV" all map to living room
7. "boys room", "kids room", "boys" all map to boys room
8. "master", "bedroom", "master bedroom", "our room" all map to master bedroom
9. "all", "all TVs", "everywhere", "every room", "all rooms" map to room "all" with entity_id "all"

Respond with ONLY valid JSON (no code blocks, no extra text):
{
  "action": "play" | "pause" | "resume" | "stop" | "error",
  "media_type": "MOVIE" | "EPISODE" | "VIDEO" | null,
  "title": "media title or null",
  "season": null or number,
  "episode": null or number,
  "library": "movies" | "tv" | "p90x" | "youtube" | null,
  "room": "living room" | "boys room" | "master" | "all" | null,
  "entity_id": "the full media_player entity_id, or \"all\" for all TVs, or null",
  "error": "friendly error message or null"
}`;

const apiBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 500,
  messages: [
    { role: 'user', content: userText }
  ],
  system: systemPrompt
};

return [{
  json: {
    apiBody,
    userText,
    conversationId,
    hasError: false
  }
}];

const response = $input.first().json;
const userText = $('Build Claude Prompt').first().json.userText;
const conversationId = $('Build Claude Prompt').first().json.conversationId;

if (response.error) {
  return [{
    json: {
      action: 'error',
      error: 'Sorry, I had trouble understanding that. Please try again.',
      userText, conversationId
    }
  }];
}

let claudeText = '';
if (response.content && response.content.length > 0) {
  claudeText = response.content[0].text.trim();
}

if (!claudeText) {
  return [{
    json: {
      action: 'error',
      error: 'Sorry, I did not get a response. Please try again.',
      userText, conversationId
    }
  }];
}

let parsed;
try {
  parsed = JSON.parse(claudeText);
} catch (e) {
  const jsonMatch = claudeText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[1].trim());
  } else {
    const objMatch = claudeText.match(/\{[\s\S]*\}/);
    if (objMatch) {
      parsed = JSON.parse(objMatch[0]);
    } else {
      return [{
        json: {
          action: 'error',
          error: 'Sorry, I could not process that command. Please try again.',
          userText, conversationId
        }
      }];
    }
  }
}

// Expand "all" into the array of all three entity_ids
if (parsed.entity_id === 'all') {
  parsed.entity_id = [
    'media_player.plex_plex_for_samsung_tv_2021',
    'media_player.plex_plex_for_samsung_tv_2021_2',
    'media_player.master_tv'
  ];
}

// Build HA-compatible media_content_id and media_content_type for Plex
if (parsed.action === 'play' && parsed.title) {
  const libraryMap = {
    'movies': 'Movies',
    'tv': 'TV Shows',
    'p90x': 'P90X',
    'youtube': 'YouTube'
  };
  const libraryName = libraryMap[parsed.library] || 'Movies';

  // HA Plex media_content_type: movie, EPISODE, video
  const contentTypeMap = {
    'movies': 'movie',
    'tv': 'EPISODE',
    'p90x': 'video',
    'youtube': 'video'
  };
  parsed.ha_content_type = contentTypeMap[parsed.library] || 'movie';

  let contentId;
  if (parsed.library === 'tv') {
    contentId = {
      'library_name': libraryName,
      'show_name': parsed.title
    };
    if (parsed.season) contentId['season_number'] = parsed.season;
    if (parsed.episode) contentId['episode_number'] = parsed.episode;
  } else {
    contentId = {
      'library_name': libraryName,
      'title': parsed.title
    };
  }
  parsed.ha_content_id = JSON.stringify(contentId);
}

return [{
  json: {
    ...parsed,
    userText,
    conversationId
  }
}];

const haResponse = $input.first().json;
const parsed = $('Parse Command').first().json;

const haFailed = haResponse.error || haResponse.statusCode >= 400;
const isAll = parsed.room === 'all';

if (haFailed) {
  // Detect Plex timeout - playback likely started but TV was slow to respond
  const errorMsg = haResponse.error?.message || haResponse.error?.stack || '';
  const isTimeout = errorMsg.includes('ReadTimeout') || errorMsg.includes('timed out') || errorMsg.includes('timeout') || errorMsg.includes('ETIMEDOUT');

  if (isTimeout && parsed.action === 'play') {
    const where = isAll ? 'on all TVs' : `in the ${parsed.room}`;
    return [{
      json: {
        success: true,
        speech: `Playing ${parsed.title} ${where}. Playback should start shortly.`,
        action: parsed.action,
        title: parsed.title,
        room: parsed.room,
        entity_id: parsed.entity_id,
        conversation_id: parsed.conversationId,
        note: 'Plex timed out but playback likely started'
      }
    }];
  }

  const errorDetail = haResponse.message || haResponse.error || 'Unknown HA error';
  const target = isAll ? 'all TVs' : `the ${parsed.room} TV`;
  return [{
    json: {
      success: false,
      speech: `Sorry, I could not ${parsed.action} on ${target}. Home Assistant returned an error.`,
      action: parsed.action,
      room: parsed.room,
      error: errorDetail,
      conversation_id: parsed.conversationId
    }
  }];
}

let speech = '';
switch (parsed.action) {
  case 'play':
    speech = isAll
      ? `Now playing ${parsed.title} on all TVs.`
      : `Now playing ${parsed.title}${parsed.room ? ' in the ' + parsed.room : ''}.`;
    break;
  case 'pause':
    speech = isAll ? 'Paused all TVs.' : `Paused the ${parsed.room} TV.`;
    break;
  case 'resume':
    speech = isAll ? 'Resumed playback on all TVs.' : `Resumed playback on the ${parsed.room} TV.`;
    break;
  case 'stop':
    speech = isAll ? 'Stopped all TVs.' : `Stopped the ${parsed.room} TV.`;
    break;
}

return [{
  json: {
    success: true,
    speech,
    action: parsed.action,
    title: parsed.title,
    room: parsed.room,
    entity_id: parsed.entity_id,
    conversation_id: parsed.conversationId
  }
}];

const input = $input.first().json;

const errorMessage = input.error || 'Sorry, I did not understand that command. Try saying something like "play The Matrix in the living room" or "pause the boys room TV".';

return [{
  json: {
    success: false,
    speech: errorMessage,
    action: input.action || 'error',
    conversation_id: input.conversationId || input.conversation_id || ''
  }
}];
